import{_ as o,C as E,o as l,c as r,a2 as e,E as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"协议层笔记：流式输出之外，还要能恢复","description":"","frontmatter":{},"headers":[],"relativePath":"agent/protocol-layer-notes.md","filePath":"agent/protocol-layer-notes.md","lastUpdated":1782915681000}'),n={name:"agent/protocol-layer-notes.md"};function A(B,a,p,d,s,c){const t=E("Mermaid");return l(),r("div",null,[a[0]||(a[0]=e('<h1 id="协议层笔记-流式输出之外-还要能恢复" tabindex="-1">协议层笔记：流式输出之外，还要能恢复 <a class="header-anchor" href="#协议层笔记-流式输出之外-还要能恢复" aria-label="Permalink to &quot;协议层笔记：流式输出之外，还要能恢复&quot;">​</a></h1><p>我最开始以为协议层就是把 token 流给前端。后来发现，对 Agent 来说，文本流只是很小的一部分。</p><p>Agent 运行过程中会产生文本、推理、工具调用、工具结果、状态变化、用户确认、产物、错误、取消、完成。前端不仅要看到过程，还要能在刷新或断线后恢复。协议层如果没设计好，后面前后端会被各种临时字段绑死。</p><h2 id="早期方案的问题" tabindex="-1">早期方案的问题 <a class="header-anchor" href="#早期方案的问题" aria-label="Permalink to &quot;早期方案的问题&quot;">​</a></h2><p>最早的流式协议很简单：delta、tool、done。</p><p>这对普通聊天足够，但对 Agent 不够：</p><ul><li>工具调用需要展示参数、状态、结果、错误。</li><li>等待用户确认不是普通消息，而是运行暂停。</li><li>产物不是文本，需要独立事件承载。</li><li>检索来源、子任务状态、状态增量都不是 token。</li><li>实时流断了以后，前端需要从持久事件恢复。</li></ul><p>如果前端直接理解后端内部对象，短期很快，长期很难维护。协议应该是稳定契约，而不是内部实现的镜像。</p><h2 id="我现在的协议分层" tabindex="-1">我现在的协议分层 <a class="header-anchor" href="#我现在的协议分层" aria-label="Permalink to &quot;我现在的协议分层&quot;">​</a></h2>',9)),i(t,{code:"flowchart%20TD%0A%20%20%20%20Runtime%5B%22%E6%89%A7%E8%A1%8C%E7%B3%BB%E7%BB%9F%22%5D%20--%3E%20Writer%5B%22%E4%BA%8B%E4%BB%B6%E5%86%99%E5%85%A5%E5%99%A8%22%5D%0A%20%20%20%20Writer%20--%3E%20Standard%5B%22%E6%A0%87%E5%87%86%E8%BF%90%E8%A1%8C%E4%BA%8B%E4%BB%B6%3Cbr%2F%3E%E6%96%87%E6%9C%AC%E3%80%81%E5%B7%A5%E5%85%B7%E3%80%81%E7%8A%B6%E6%80%81%E3%80%81%E7%BB%88%E6%80%81%22%5D%0A%20%20%20%20Writer%20--%3E%20Extension%5B%22%E6%89%A9%E5%B1%95%E4%BA%8B%E4%BB%B6%3Cbr%2F%3E%E4%BA%A7%E7%89%A9%E3%80%81%E6%A3%80%E7%B4%A2%E6%9D%A5%E6%BA%90%E3%80%81%E5%AD%90%E8%BF%90%E8%A1%8C%22%5D%0A%0A%20%20%20%20Standard%20--%3E%20Live%5B%22%E5%AE%9E%E6%97%B6%E9%80%9A%E9%81%93%22%5D%0A%20%20%20%20Extension%20--%3E%20Live%0A%20%20%20%20Standard%20--%3E%20Durable%5B%22%E6%8C%81%E4%B9%85%E4%BA%8B%E4%BB%B6%22%5D%0A%20%20%20%20Extension%20--%3E%20Durable%0A%0A%20%20%20%20Live%20--%3E%20UI%5B%22%E5%89%8D%E7%AB%AF%E5%AE%9E%E6%97%B6%E6%B8%B2%E6%9F%93%22%5D%0A%20%20%20%20Durable%20--%3E%20Projection%5B%22%E5%8E%86%E5%8F%B2%E6%8A%95%E5%BD%B1%20%2F%20%E7%8A%B6%E6%80%81%E5%BF%AB%E7%85%A7%22%5D%0A%20%20%20%20Projection%20--%3E%20UI%0A"}),a[1]||(a[1]=e('<p>实时通道服务体验，持久事件服务恢复和审计。两者最好来自同一套事件语义。</p><p>标准事件承载通用语义，自有扩展承载业务语义。扩展要有命名空间和版本意识，不要随手往标准字段里塞东西。</p><h2 id="协议不只面向前端" tabindex="-1">协议不只面向前端 <a class="header-anchor" href="#协议不只面向前端" aria-label="Permalink to &quot;协议不只面向前端&quot;">​</a></h2><p>Agent 平台里至少有几类协议边界：</p><p>运行事件协议面向前端和恢复。工具协议面向外部能力发现和调用。Skill 协议面向任务操作知识。Agent 间协议面向远端协作。</p><p>这些协议不能互相替代，也不应该全部写进主循环。</p><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>第一个坑，是把实时流当事实源。实时流会断、会过期、会丢消息。恢复和审计必须依赖持久事件。</p><p>第二个坑，是事件字段随手加。今天加一个 <code>statusText</code>，明天加一个 <code>extraData</code>，后面没人知道语义边界。</p><p>第三个坑，是标准协议和扩展混在一起。扩展可以有，但要明确命名空间，不要污染通用事件。</p><p>第四个坑，是让前端猜状态。前端应该消费协议事件和快照，而不是猜后端执行到了哪一步。</p><p>第五个坑，是外部协议直接进主流程。工具、Skill、远端 Agent 都应该先适配成内部统一抽象，再参与执行。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果重新做协议层，我会从第一天定义事件 schema。哪怕事件很少，也要语义清楚。</p><p>断线恢复也要早做。只要有流式输出，就一定会遇到刷新、重连、多端状态不一致。</p><p>一句话总结：协议层不是传输细节，而是执行系统、前端体验和外部能力之间的边界。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>为什么 token stream 不够表达 Agent 运行。</li><li>实时流和持久事件分别解决什么。</li><li>标准事件和扩展事件如何划边界。</li><li>前端为什么不应该理解内部对象。</li><li>工具协议、Skill 协议、Agent 间协议各自负责什么。</li><li>断线恢复为什么要从协议层设计。</li><li>如果重做，我会先定义事件 schema。</li></ol>',18))])}const u=o(n,[["render",A]]);export{_ as __pageData,u as default};
